const data = $input.first()?.json || {};
const predictions = data.predictions || [];
const topRec = data.top_recommendation || '';
const outlook = data.market_outlook || '';

const highConf = predictions.filter(p => p.confidence === 'HIGH' || p.confidence === 'MEDIUM');

if (highConf.length === 0) {
  return [{ json: { skip: true, reason: 'No high/medium confidence predictions today' } }];
}

const top5 = highConf.slice(0, 5);
const bulletList = top5.map((p, i) => 
  `${i+1}. [${p.confidence}] ${p.requirement} - ${p.agency} (${p.timeline}) > ${p.gda_unit}: ${p.prep_action}`
).join('; ');

const description = `PROACTIVE INTEL - ${new Date().toLocaleDateString()}. Market: ${outlook}. Top Predictions: ${bulletList}. Top Recommendation: ${topRec}`;

return [{ json: {
  skip: false,
  title: `[PROACTIVE] ${highConf.length} predicted requirements detected`,
  description: description,
  prediction_count: highConf.length,
  predictions: top5,
  top_recommendation: topRec
} }];

if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];
